#!/usr/bin/env bash
# maw team-agent plugin installer — v1.2.0
# Latest: --model brackets fix (1M context modifier)
set -euo pipefail
DST="$HOME/.maw/plugins/team-agent"
BACKUP_ROOT="$HOME/.maw/plugin-backups"
echo "📦 installing maw team-agent v1.2.0 → $DST"
if [ -d "$DST" ]; then
  mkdir -p "$BACKUP_ROOT"
  BACKUP="$BACKUP_ROOT/team-agent-$(date +%s)"
  echo "  → existing install found, backing up to $BACKUP"
  mv "$DST" "$BACKUP"
fi
mkdir -p "$DST/cmd" "$DST/lib"
write_file() {
  local path="$1"
  local b64="$2"
  echo "$b64" | base64 -d > "$DST/$path"
  echo "  ✓ $path"
}
write_file 'plugin.json' ''
write_file 'package.json' ''
write_file 'tsconfig.json' ''
write_file 'index.ts' ''
write_file 'impl.ts' ''
write_file 'impl.test.ts' ''
write_file 'cmd/help.ts' ''
write_file 'cmd/team.ts' ''
write_file 'cmd/uuid.ts' ''
write_file 'cmd/cleanup.ts' ''
write_file 'cmd/charter.ts' ''
write_file 'cmd/wizard.ts' ''
write_file 'cmd/bring.ts' ''
write_file 'cmd/tutorial.ts' ''
write_file 'lib/uuid.ts' ''
write_file 'lib/config.ts' ''
write_file 'lib/helpers.ts' ''
write_file 'lib/yaml.ts' ''
write_file 'lib/presets.ts' ''
echo ""
echo "✅ installed maw team-agent v1.2.0 (19 files)"
echo "  latest: --model brackets fix (1M context modifier)"
